const body = $input.item.json;
const ts = new Date().toISOString();
const id = 'ARC-' + ts.replace(/[-:.TZ]/g, '').slice(0, 12);

return {
  json: {
    input_id: id,
    source: body.source || 'Unknown',
    raw_message: body.raw_message || '',
    received_at: ts
  }
};

const d = $input.item.json;

const systemPrompt = 'You are a support ticket classifier for ArcVault, a B2B SaaS platform. Analyze inbound customer messages and classify them accurately. Respond with valid JSON only. No markdown, no explanation.';

const userPrompt = 'Classify the customer message below.\n\nSource: ' + d.source + '\nMessage: ' + d.raw_message + '\n\nReturn JSON with these exact fields:\n- category: one of Bug Report, Feature Request, Billing Issue, Technical Question, Incident/Outage\n- priority: Low, Medium, or High\n- confidence_score: float between 0.0 and 1.0\n\nPriority rules:\n  High = service down, multiple users affected, data loss risk, billing error\n  Medium = single user blocked, compliance need, billing discrepancy\n  Low = general inquiry, feature suggestion, non-urgent question\n\nConfidence rules:\n  0.90-1.0 = message clearly maps to one category\n  0.70-0.89 = mostly clear with minor ambiguity\n  0.50-0.69 = could reasonably fit multiple categories\n  below 0.50 = insufficient information to classify';

return {
  json: {
    ...d,
    groq_body: {
      model: 'llama-3.3-70b-versatile',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.1,
      response_format: { type: 'json_object' }
    }
  }
};

const response = $input.item.json;
const rawContent = response.choices[0].message.content;
const cleaned = rawContent.replace(/```(?:json)?\n?|\n?```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { category: 'Unrecognized', priority: 'Medium', confidence_score: 0.0 };
}

const prev = $('Normalize Input').item.json;

return {
  json: {
    input_id: prev.input_id,
    source: prev.source,
    raw_message: prev.raw_message,
    received_at: prev.received_at,
    category: parsed.category || 'Unrecognized',
    priority: parsed.priority || 'Medium',
    confidence_score: typeof parsed.confidence_score === 'number' ? parsed.confidence_score : 0.0
  }
};

const d = $input.item.json;

const systemPrompt = 'You are a support ticket enrichment agent for ArcVault, a B2B SaaS platform. Extract structured information to help the receiving team act immediately. Respond with valid JSON only. No markdown, no explanation.';

const userPrompt = 'Extract structured information from the customer message below.\n\nSource: ' + d.source + '\nMessage: ' + d.raw_message + '\nCategory: ' + d.category + '\nPriority: ' + d.priority + '\n\nReturn JSON with these exact fields:\n- core_issue: one sentence describing what the customer needs\n- identifiers: object with account_id, invoice_number, error_code, other (each extracted or null)\n- urgency_signal: one of Immediate, Same-day, Next-business-day, No urgency\n- billing_delta: numeric dollar difference if a billing discrepancy is mentioned, else null\n- escalation_keywords_found: array of any matching phrases found: outage, down for all users, multiple users affected\n- summary: 2-3 sentences for the receiving team, written in third person, actionable tone\n\nUrgency rules:\n  Immediate = outage, multiple users affected, security incident\n  Same-day = single user blocked, billing dispute\n  Next-business-day = compliance need, integration evaluation\n  No urgency = general question, feature suggestion';

return {
  json: {
    ...d,
    groq_body: {
      model: 'llama-3.3-70b-versatile',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.1,
      response_format: { type: 'json_object' }
    }
  }
};

const response = $input.item.json;
const rawContent = response.choices[0].message.content;
const cleaned = rawContent.replace(/```(?:json)?\n?|\n?```/g, '').trim();

let enrichment;
try {
  enrichment = JSON.parse(cleaned);
} catch(e) {
  enrichment = {
    core_issue: 'Enrichment parsing failed — manual review required',
    identifiers: { account_id: null, invoice_number: null, error_code: null, other: null },
    urgency_signal: 'Same-day',
    billing_delta: null,
    escalation_keywords_found: [],
    summary: 'Enrichment parsing failed. Manual review required.'
  };
}

const prev = $('Parse Classification').item.json;

const ROUTING_MAP = {
  'Bug Report': 'Engineering',
  'Incident/Outage': 'Engineering',
  'Billing Issue': 'Billing',
  'Feature Request': 'Product',
  'Technical Question': 'IT/Security'
};

const standardDestination = ROUTING_MAP[prev.category] || 'General';
const escalationReasons = [];

if (prev.confidence_score < 0.70) {
  escalationReasons.push('low_confidence:' + prev.confidence_score);
}
if ((enrichment.escalation_keywords_found || []).length > 0) {
  escalationReasons.push('keywords:' + enrichment.escalation_keywords_found.join(','));
}
if (enrichment.billing_delta !== null && enrichment.billing_delta !== undefined && enrichment.billing_delta > 500) {
  escalationReasons.push('billing_delta:$' + enrichment.billing_delta);
}

const isEscalated = escalationReasons.length > 0;

return {
  json: {
    input_id: prev.input_id,
    source: prev.source,
    raw_message: prev.raw_message,
    received_at: prev.received_at,
    category: prev.category,
    priority: prev.priority,
    confidence_score: prev.confidence_score,
    core_issue: enrichment.core_issue,
    identifiers: JSON.stringify(enrichment.identifiers),
    urgency_signal: enrichment.urgency_signal,
    billing_delta: enrichment.billing_delta,
    escalation_keywords_found: JSON.stringify(enrichment.escalation_keywords_found || []),
    destination_queue: isEscalated ? 'Escalation' : standardDestination,
    standard_destination: standardDestination,
    is_escalated: isEscalated,
    escalation_reasons: JSON.stringify(escalationReasons),
    summary: enrichment.summary,
    processed_at: new Date().toISOString()
  }
};
